  ('social-worker-moex-00045', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關英國貝弗里奇報告書內容的敘述，以下何者有誤？', '["應提供兒童津貼", "應提供已婚婦女的各種補助", "應提供全面性的健康與復健服務", "應提供退伍軍人各種補助"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00046', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關充權（empowerment）的社會工作服務，下列敘述何者錯誤？', '["社會工作開始思考成為多專業專家", "其目的是要讓服務對象掌控自己的生活", "旨在建立一種由服務對象主導的互動基調", "強調把握機會發展服務對象的批判性思考"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00047', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的實踐離不開人權發展，尤其關注弱勢者人權，有關社會工作的人權實踐敘述，下列何 者錯誤？', '["弱勢者由於缺乏經濟、政治和發展機會而處於不利的社會地位，因此社會工作需致力於結構與 制度之改善", "社會工作應透過倡導、社會行動、充權的整合策略與運用，為弱勢者爭取應有權益", "不論服務對象是個人、家庭、社區，問題取向的直接服務是主要工作方式", "傳統的社會工作常被批評為國家權力控制的工具，因此社會工作者對於自身立場需經常檢視反思"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00048', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '一位社會工作者觀察到數位時代來臨，希望幫助自己的服務對象提升數位使用能力，以促進生活的 便利性，因此決定辦理「數位工具操作教學」。上述情境此社會工作者欲發揮何項社會工作的功能？', '["恢復的功能", "預防的功能", "發展的功能", "補救的功能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00049', 'social-worker', 'social-worker-moex-114-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Boehm（1959）認為社會工作有一些基本假設，下列何者錯誤？', '["社會工作如同其他專業，具有問題解決的功能", "社會工作實施所根據的價值，仰賴社會工作者個人的價值觀", "社會工作實施所需要的知識，取決於其實施的目標及需要解決問題的本質", "社會工作的科學基礎，包括已驗證知識與假設的理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "94a8952cb470", "answer_pdf_sha1": "e7b3bb4d7f68", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
